import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const runtimeDir = path.resolve(__dirname, "../src/codegen/runtime");
const files = fs.readdirSync(runtimeDir).filter((f) => f.endsWith(".ts"));

let out = "// AUTO-GENERATED BY scripts/bundle-templates.js\n// @ts-nocheck\n\n";
let dtsOut = "// AUTO-GENERATED BY scripts/bundle-templates.js\n\n";

for (const file of files) {
  const content = fs.readFileSync(path.join(runtimeDir, file), "utf-8");
  const cleaned = content
    .replace("// @ts-nocheck\n", "")
    .replace(/\\/g, "\\\\")
    .replace(/\`/g, "\\`")
    .replace(/\$/g, "\\$");
  const varName = file.replace(".ts", "Code");
  out += `export const ${varName} = \`${cleaned}\`;\n\n`;
  dtsOut += `export declare const ${varName}: string;\n`;
}

// Also bundle the JS wrapper template, compiling it at build-time
import ts from "typescript";

const wrapperTemplatePath = path.resolve(__dirname, "../src/bindings/javascript/bindings.ts");
if (fs.existsSync(wrapperTemplatePath)) {
  const content = fs.readFileSync(wrapperTemplatePath, "utf-8");

  const options = {
    module: ts.ModuleKind.ESNext,
    target: ts.ScriptTarget.ES2022,
    declaration: true,
  };

  const createdFiles = {};
  const host = ts.createCompilerHost(options);
  const originalGetSourceFile = host.getSourceFile;
  host.getSourceFile = (fileName, languageVersion, onError, shouldCreateNewSourceFile) => {
    if (fileName === "bindings.ts") {
      return ts.createSourceFile(fileName, content, languageVersion);
    }
    return originalGetSourceFile(fileName, languageVersion, onError, shouldCreateNewSourceFile);
  };
  host.writeFile = (fileName, contents) => {
    createdFiles[fileName] = contents;
  };

  const program = ts.createProgram(["bindings.ts"], options, host);
  program.emit();

  const jsCode = createdFiles["bindings.js"] || "";
  const dtsCode = createdFiles["bindings.d.ts"] || "";

  const jsCleaned = jsCode.replace(/\\/g, "\\\\").replace(/\`/g, "\\`").replace(/\$/g, "\\$");
  const dtsCleaned = dtsCode.replace(/\\/g, "\\\\").replace(/\`/g, "\\`").replace(/\$/g, "\\$");

  out += `export const bindingsTemplateJsCode = \`${jsCleaned}\`;\n\n`;
  out += `export const bindingsTemplateDtsCode = \`${dtsCleaned}\`;\n\n`;
  dtsOut += `export declare const bindingsTemplateJsCode: string;\n`;
  dtsOut += `export declare const bindingsTemplateDtsCode: string;\n`;
}

// Write the JS file
const outDir = path.resolve(__dirname, "../build/src-gen");
if (!fs.existsSync(outDir)) {
  fs.mkdirSync(outDir, { recursive: true });
}
const jsOutPath = path.resolve(outDir, "runtime-templates.js");
fs.writeFileSync(jsOutPath, out, "utf-8");

// Write the DTS file
const dtsOutPath = path.resolve(outDir, "runtime-templates.d.ts");
fs.writeFileSync(dtsOutPath, dtsOut, "utf-8");

console.log(`Bundled templates into ${outDir}`);
